// App.js
import React, { useState, useEffect } from 'react';
import Login from './Login';
import Dashboard from './Dashboard';

const App = () => {
  const [accessToken, setAccessToken] = useState(null);
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const token = localStorage.getItem('access_token');
    const expiresAt = localStorage.getItem('expires_at');
    const storedUser = localStorage.getItem('user');

    if (token && expiresAt && Date.now() < parseInt(expiresAt)) {
      setAccessToken(token);
      if (storedUser) {
        setUser(JSON.parse(storedUser));
      }
    } else {
      localStorage.removeItem('access_token');
      localStorage.removeItem('expires_at');
      localStorage.removeItem('user');
    }
    setLoading(false);
  }, []);

  const handleLogin = (token, userData) => {
    setAccessToken(token);
    setUser(userData);
  };

  const handleLogout = () => {
    localStorage.removeItem('access_token');
    localStorage.removeItem('expires_at');
    localStorage.removeItem('user');
    setAccessToken(null);
    setUser(null);
  };

  if (loading) {
    return <div>Loading...</div>;
  }

  return (
    <div>
      {accessToken ? (
        <Dashboard user={user} token={accessToken} onLogout={handleLogout} />
      ) : (
        <Login onLogin={handleLogin} />
      )}
    </div>
  );
};

export default App;

// Login.js
import React, { useEffect } from 'react';
import { parseTokenFromUrl, initiateOAuthFlow } from './oauthUtils';

const Login = ({ onLogin }) => {
  useEffect(() => {
    const handleCallback = async () => {
      const hash = window.location.hash;
      
      if (hash) {
        const tokenData = parseTokenFromUrl(hash);
        
        if (tokenData.access_token) {
          const expiresAt = Date.now() + (tokenData.expires_in * 1000);
          
          localStorage.setItem('access_token', tokenData.access_token);
          localStorage.setItem('expires_at', expiresAt.toString());
          
          try {
            const userData = await fetchUserData(tokenData.access_token);
            localStorage.setItem('user', JSON.stringify(userData));
            onLogin(tokenData.access_token, userData);
          } catch (error) {
            console.error('Error fetching user data:', error);
            onLogin(tokenData.access_token, null);
          }
          
          window.history.replaceState(null, null, window.location.pathname);
        } else if (tokenData.error) {
          console.error('OAuth error:', tokenData.error, tokenData.error_description);
          alert('Authentication failed: ' + (tokenData.error_description || tokenData.error));
        }
      }
    };

    handleCallback();
  }, [onLogin]);

  const fetchUserData = async (token) => {
    const response = await fetch('https://your-auth-provider.com/userinfo', {
      headers: {
        'Authorization': `Bearer ${token}`
      }
    });
    
    if (!response.ok) {
      throw new Error('Failed to fetch user data');
    }
    
    return response.json();
  };

  const handleLoginClick = () => {
    initiateOAuthFlow();
  };

  return (
    <div style={{ padding: '40px', textAlign: 'center' }}>
      <h1>Welcome to OAuth SPA</h1>
      <p>Please log in to continue</p>
      <button 
        onClick={handleLoginClick}
        style={{
          padding: '10px 20px',
          fontSize: '16px',
          backgroundColor: '#4285f4',
          color: 'white',
          border: 'none',
          borderRadius: '4px',
          cursor: 'pointer'
        }}
      >
        Login with OAuth
      </button>
    </div>
  );
};

export default Login;

// Dashboard.js
import React, { useState, useEffect } from 'react';

const Dashboard = ({ user, token, onLogout }) => {
  const [data, setData] = useState(null);

  useEffect(() => {
    const expiresAt = localStorage.getItem('expires_at');
    if (expiresAt && Date.now() >= parseInt(expiresAt)) {
      alert('Your session has expired. Please log in again.');
      onLogout();
      return;
    }

    const checkTokenExpiration = setInterval(() => {
      const expiresAt = localStorage.getItem('expires_at');
      if (expiresAt && Date.now() >= parseInt(expiresAt)) {
        alert('Your session has expired. Please log in again.');
        onLogout();
      }
    }, 60000);

    return () => clearInterval(checkTokenExpiration);
  }, [onLogout]);

  const fetchProtectedData = async () => {
    try {
      const response = await fetch('https://your-api.com/protected-resource', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      
      if (!response.ok) {
        if (response.status === 401) {
          alert('Token expired or invalid. Please log in again.');
          onLogout();
          return;
        }
        throw new Error('Failed to fetch data');
      }
      
      const result = await response.json();
      setData(result);
    } catch (error) {
      console.error('Error fetching protected data:', error);
      alert('Error fetching data: ' + error.message);
    }
  };

  return (
    <div style={{ padding: '40px' }}>
      <h1>Dashboard</h1>
      {user && (
        <div style={{ marginBottom: '20px' }}>
          <h2>Welcome, {user.name || user.email || 'User'}</h2>
          {user.email && <p>Email: {user.email}</p>}
        </div>
      )}
      
      <div style={{ marginBottom: '20px' }}>
        <button 
          onClick={fetchProtectedData}
          style={{
            padding: '10px 20px',
            fontSize: '16px',
            backgroundColor: '#34a853',
            color: 'white',
            border: 'none',
            borderRadius: '4px',
            cursor: 'pointer',
            marginRight: '10px'
          }}
        >
          Fetch Protected Data
        </button>
        
        <button 
          onClick={onLogout}
          style={{
            padding: '10px 20px',
            fontSize: '16px',
            backgroundColor: '#ea4335',
            color: 'white',
            border: 'none',
            borderRadius: '4px',
            cursor: 'pointer'
          }}
        >
          Logout
        </button>
      </div>

      {data && (
        <div style={{ 
          marginTop: '20px', 
          padding: '20px', 
          backgroundColor: '#f5f5f5',
          borderRadius: '4px'
        }}>
          <h3>Protected Data:</h3>
          <pre>{JSON.stringify(data, null, 2)}</pre>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

// oauthUtils.js
const OAUTH_CONFIG = {
  authorizationEndpoint: 'https://your-auth-provider.com/oauth/authorize',
  clientId: 'your-client-id',
  redirectUri: window.location.origin,
  scope: 'openid profile email',
  responseType: 'token'
};

export const initiateOAuthFlow = () => {
  const state = generateRandomString(32);
  const nonce = generateRandomString(32);
  
  sessionStorage.setItem('oauth_state', state);
  sessionStorage.setItem('oauth_nonce', nonce);

  const params = new URLSearchParams({
    response_type: OAUTH_CONFIG.responseType,
    client_id: OAUTH_CONFIG.clientId,
    redirect_uri: OAUTH_CONFIG.redirectUri,
    scope: OAUTH_CONFIG.scope,
    state: state,
    nonce: nonce
  });

  const authUrl = `${OAUTH_CONFIG.authorizationEndpoint}?${params.toString()}`;
  window.location.href = authUrl;
};

export const parseTokenFromUrl = (hash) => {
  const params = new URLSearchParams(hash.substring(1));
  
  const tokenData = {
    access_token: params.get('access_token'),
    token_type: params.get('token_type'),
    expires_in: params.get('expires_in') ? parseInt(params.get('expires_in')) : 3600,
    scope: params.get('scope'),
    state: params.get('state'),
    error: params.get('error'),
    error_description: params.get('error_description')
  };

  const storedState = sessionStorage.getItem('oauth_state');
  
  if (tokenData.state && tokenData.state !== storedState) {
    console.error('State mismatch - possible CSRF attack');
    return { error: 'state_mismatch', error_description: 'Invalid state parameter' };
  }

  sessionStorage.removeItem('oauth_state');
  sessionStorage.removeItem('oauth_nonce');

  return tokenData;
};

const generateRandomString = (length) => {
  const charset = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
  let result = '';
  const randomValues = new Uint8Array(length);
  window.crypto.getRandomValues(randomValues);
  
  for (let i = 0; i < length; i++) {
    result += charset[randomValues[i] % charset.length];
  }
  
  return result;
};

export const isTokenValid = () => {
  const expiresAt = localStorage.getItem('expires_at');
  return expiresAt && Date.now() < parseInt(expiresAt);
};

